'use client';

import { useEffect, useRef } from 'react';

export default function AnimatedTopography() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let time = 0;
    
    // Line Configuration
    const numLines = 35;
    const segments = 100;
    
    // Mouse state
    let mouseX = -1000;
    let mouseY = -1000;
    let targetMouseX = -1000;
    let targetMouseY = -1000;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    window.addEventListener('resize', resize);
    resize();

    const onMouseMove = (e: MouseEvent) => {
      targetMouseX = e.clientX;
      targetMouseY = e.clientY;
    };

    const onMouseLeave = () => {
      targetMouseX = -1000;
      targetMouseY = -1000;
    };

    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseout', onMouseLeave);

    const render = () => {
      time += 0.005;
      
      // Smooth mouse interpolation
      mouseX += (targetMouseX - mouseX) * 0.1;
      mouseY += (targetMouseY - mouseY) * 0.1;

      // Clear canvas (opaque black)
      ctx.fillStyle = '#000000';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      ctx.lineWidth = 1.5;
      ctx.strokeStyle = 'rgba(255, 255, 255, 0.45)'; // More visible subtle white

      
      const segmentWidth = canvas.width / segments;
      const verticalSpacing = canvas.height / numLines;

      for (let i = 0; i < numLines; i++) {
        ctx.beginPath();
        
        const baseY = i * verticalSpacing;
        
        for (let j = 0; j <= segments; j++) {
          const x = j * segmentWidth;
          
          // Organic Math Waves
          const wave1 = Math.sin(j * 0.05 + time + i * 0.1) * 30;
          const wave2 = Math.cos(j * 0.08 - time * 1.5) * 15;
          let y = baseY + wave1 + wave2;

          // Mouse Repulsion Effect
          const dx = x - mouseX;
          const dy = y - mouseY;
          const distance = Math.sqrt(dx * dx + dy * dy);
          const maxDistance = 250;

          if (distance < maxDistance) {
            // Inverse distance calculation to push lines away
            const force = (1 - distance / maxDistance);
            // Push direction mostly on Y axis for dramatic topographical parting
            const pushY = (dy / distance) * force * 100;
            y += pushY;
          }

          if (j === 0) {
            ctx.moveTo(x, y);
          } else {
            // Simple line to since we use high segment counts (curveTo is heavier)
            ctx.lineTo(x, y);
          }
        }
        
        ctx.stroke();
      }

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    return () => {
      window.removeEventListener('resize', resize);
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseout', onMouseLeave);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas 
      ref={canvasRef} 
      className="fixed inset-0 z-0 pointer-events-none"
    />
  );
}
